// Fonction pour ajuster une date au prochain jour ouvrable (lundi-vendredi)
function adjustToWorkingDay(date) {
  const day = date.getDay(); // 0 = dimanche, 1 = lundi, ..., 6 = samedi

  if (day === 0) { // Dimanche → Lundi
    date.setDate(date.getDate() + 1);
  } else if (day === 6) { // Samedi → Lundi
    date.setDate(date.getDate() + 2);
  }

  return date;
}

// Fonction pour ajouter des jours ouvrables seulement
function addWorkingDays(startDate, daysToAdd) {
  const date = new Date(startDate);
  let addedDays = 0;

  while (addedDays < daysToAdd) {
    date.setDate(date.getDate() + 1);
    const dayOfWeek = date.getDay();

    // Si c'est un jour ouvrable (lundi = 1 à vendredi = 5)
    if (dayOfWeek >= 1 && dayOfWeek <= 5) {
      addedDays++;
    }
  }

  return date;
}

// Traitement des items
return items.map(item => {
  try {
    // 📅 ÉTAPE 1: Récupération de la date de départ
    const startDateStr = item.json.Start?.date?.start;
    if (!startDateStr) {
      throw new Error('Date de Start manquante');
    }

    const startDate = new Date(startDateStr + 'T00:00:00.000Z');
    const repeatNb = item.json["Répéter Nb"] || 0;

    // 📅 ÉTAPE 2: Calcul de "New Date" (Start + Répéter Nb jours)
    let newDate = new Date(startDate);
    newDate.setDate(newDate.getDate() + repeatNb);

    // 📅 ÉTAPE 3: Ajuster "New Date" au jour ouvrable
    newDate = adjustToWorkingDay(newDate);

    // 📅 ÉTAPE 4: Calcul de "New Dead line" (New Date + Répéter Nb jours calendaires puis ajuster)
    let newDeadline = new Date(newDate);
    newDeadline.setDate(newDeadline.getDate() + repeatNb);
    newDeadline = adjustToWorkingDay(newDeadline);

    // 📊 RÉSULTATS: Ajout des nouvelles propriétés
    item.json["New Date"] = {
      "date": {
        "start": newDate.toISOString().split('T')[0],
        "end": null,
        "time_zone": null
      }
    };

    item.json["New Dead line"] = {
      "date": {
        "start": newDeadline.toISOString().split('T')[0],
        "end": null,
        "time_zone": null
      }
    };

    // 🐛 DEBUG: Informations utiles
    item.json["_debug"] = {
      "original_start": startDateStr,
      "repeat_days": repeatNb,
      "new_date_day": ['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'][newDate.getDay()],
      "deadline_day": ['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'][newDeadline.getDay()],
      "calculation": `${startDateStr} + ${repeatNb} jours = ${newDate.toISOString().split('T')[0]} (${['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'][newDate.getDay()]}) + ${repeatNb} jours calendaires = ${newDeadline.toISOString().split('T')[0]} (${['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'][newDeadline.getDay()]})`
    };

    return item;

  } catch (error) {
    // ❌ GESTION D'ERREUR
    item.json["error"] = {
      "message": error.message,
      "timestamp": new Date().toISOString()
    };
    return item;
  }
});

